# Binary-safe Pass 4: Terminology Fixes + Death Recap UI
# Uses same Replace-Bytes function as Pass 1-3

function Replace-Bytes {
    param([byte[]]$Data, [byte[]]$Find, [byte[]]$Replace)
    $result = New-Object System.Collections.Generic.List[byte]
    $count = 0
    $i = 0
    while ($i -lt $Data.Length) {
        $match = $true
        if ($i + $Find.Length -le $Data.Length) {
            for ($j = 0; $j -lt $Find.Length; $j++) {
                if ($Data[$i + $j] -ne $Find[$j]) { $match = $false; break }
            }
        } else { $match = $false }
        if ($match) {
            foreach ($b in $Replace) { $result.Add($b) }
            $i += $Find.Length
            $count++
        } else {
            $result.Add($Data[$i])
            $i++
        }
    }
    return @{ Bytes = $result.ToArray(); Count = $count }
}

function MakeBytes([int[]]$codes) {
    if (-not $codes) { return $null }
    $s = -join ($codes | ForEach-Object { [char]$_ })
    return [System.Text.Encoding]::UTF8.GetBytes($s)
}

