$grandTotal = 0

# First restore bot_messages_en.str which was corrupted
& git -C d:\HoN_RU_Pack checkout HEAD -- bundle/bot_messages_en.str

foreach ($f in $files) {
    if ($replacements.ContainsKey($f.Name)) {
        Write-Host "`n=== $($f.Name) ==="
        $bytes = [System.IO.File]::ReadAllBytes($f.FullName)
        $fileFixes = 0
        
        foreach ($pair in $replacements[$f.Name]) {
            # pair should be an array of length 2
            if ($pair -isnot [System.Array] -or $pair.Length -lt 2) {
                Write-Host "WARNING: Unexpected pair format! Length=$($pair.Length) Type=$($pair.GetType().Name)"
                continue
            }
            $r = Replace-Bytes -Data $bytes -Find $pair[0] -Replace $pair[1]
            if ($r.Count -gt 0) {
                $bytes = $r.Bytes
                $fileFixes += $r.Count
                Write-Host "  Replaced $($r.Count) occurrences"
            }
        }
        
        if ($fileFixes -gt 0) {
            [System.IO.File]::WriteAllBytes($f.FullName, $bytes)
            Write-Host "Saved $($f.Name) ($($bytes.Length) bytes)"
            $grandTotal += $fileFixes
        }
    }
}

Write-Host "`nPass 4 complete. Total terminology fixes: $grandTotal"
